import { Diagram } from 'diagrams-js';
import { EC2 } from 'diagrams-js/aws/compute.js';
import { RDS } from 'diagrams-js/aws/database.js';
import { S3 } from 'diagrams-js/aws/storage.js';

const diagram = Diagram('Web Architecture', {
  direction: 'TB'
});

const web = diagram.add(EC2('Web Server'));
const db = diagram.add(RDS('Database'));
const storage = diagram.add(S3('Storage'));

web.to(db);
web.to(storage);

// Render SVG
document.getElementById('svg-btn').addEventListener('click', async () => {
  const svg = await diagram.render();
  document.getElementById('diagram').innerHTML = svg;
  document.getElementById('output').innerHTML = '<p>SVG rendered above</p>';
});

// Render as Data URL
document.getElementById('dataurl-btn').addEventListener('click', async () => {
  const dataUrl = await diagram.render({ dataUrl: true });
  document.getElementById('output').innerHTML = `<p>Data URL (truncated):</p><code>${dataUrl.substring(0, 100)}...</code>`;

  // Also display as image
  const img = document.createElement('img');
  img.src = dataUrl;
  img.style.maxWidth = '100%';
  document.getElementById('diagram').innerHTML = '';
  document.getElementById('diagram').appendChild(img);
});

// Render PNG (uses canvas in browser)
document.getElementById('png-btn').addEventListener('click', async () => {
  try {
    const png = await diagram.render({ format: 'png' });
    document.getElementById('output').innerHTML = `<p>PNG rendered as Uint8Array, length: ${png.length} bytes</p>`;

    // Create blob and display
    const blob = new Blob([png], { type: 'image/png' });
    const url = URL.createObjectURL(blob);
    const img = document.createElement('img');
    img.src = url;
    img.style.maxWidth = '100%';
    document.getElementById('diagram').innerHTML = '';
    document.getElementById('diagram').appendChild(img);
  } catch (err) {
    document.getElementById('output').innerHTML = `<p style='color: red'>Error: ${err.message}</p>`;
  }
});

// Initial render
const svg = await diagram.render();
document.getElementById('diagram').innerHTML = svg;
